__kernel void dynproc_kernel(const int iteration,
                             __global const int* gpuWall,
                             __global int* gpuSrc,
                             __global int* gpuDst,
                             const int cols,
                             const int rows,
                             const int startStep,
                             const int borderCols,
                             const int HALO,
                             __local int* prev,
                             __local int* result,
                             __global int* outputBuffer)
{
    (void)rows;
    (void)borderCols;
    (void)HALO;
    (void)prev;
    (void)result;
    (void)outputBuffer;

    if (get_global_id(0) != 0) return;

    __global int* bufA = gpuSrc;
    __global int* bufB = gpuDst;

    for (int k = 0; k < iteration; k++) {
        int wallBase = (startStep + k) * cols;

        for (int n = 0; n < cols; n++) {
            int m = bufA[n];
            if (n > 0) {
                int v = bufA[n - 1];
                if (v < m) m = v;
            }
            if (n < cols - 1) {
                int v = bufA[n + 1];
                if (v < m) m = v;
            }
            bufB[n] = gpuWall[wallBase + n] + m;
        }

        __global int* tmp = bufA;
        bufA = bufB;
        bufB = tmp;
    }

    if ((iteration & 1) == 0) {
        for (int n = 0; n < cols; n++) {
            gpuDst[n] = bufA[n];
        }
    }
}
